use std::collections::VecDeque;

struct Interpreter<T> {
    input_queue: VecDeque<T>,
}

impl<T: std::fmt::Debug + Clone> Interpreter<T> {
    fn new(initial_inputs: Vec<T>) -> Self {
        Interpreter { 
            input_queue: initial_inputs.into()
        }
    }

    fn process_next(&mut self) -> Option<T> {
        self.input_queue.pop_front()
    }

    fn is_empty(&self) -> bool {
        self.input_queue.is_empty()
    }
}

fn main() {
    let mut interpreter = Interpreter::new(vec![10i32, 5i32]);

    if let Some(result1) = interpreter.process_next() {
        println!("First item processed: {:?}", result1);
    }

    if let Some(result2) = interpreter.process_next() {
        println!("Second item processed: {:?}", result2);
    }

    if interpreter.is_empty() {
        println!("Interpreter queue is now empty.");
    }
}

use std::error::Error;
use std::fmt;

struct ModelConfig<T> {
    weights: T,
    input_size: usize,
}

impl<T: Clone + fmt::Debug> ModelConfig<T> {
    fn new(weights: T, input_size: usize) -> Self {
        ModelConfig { weights, input_size }
    }

    fn run_inference(&self, data: &Vec<f32>) -> Result<f32, Box<dyn Error>> {
        if data.len() != self.input_size {
            return Err(format!("Input size mismatch: expected {}, got {}", self.input_size, data.len()).into());
        }

        let mut sum = 0.0;
        for i in 0..data.len() {
            sum += data[i] as f32 * 0.5; // Simplified calculation based on weight concept
        }
        Ok(sum)
    }
}

fn main() {
    let weights_f32 = vec![1.0, 2.0];
    let config_f32: ModelConfig<Vec<f32>> = ModelConfig::new(weights_f32, 2);
    let input_data_ok = vec![0.5, 1.5];

    match config_f32.run_inference(&input_data_ok) {
        Ok(result) => println!("Inference successful with f32 weights: {}", result),
        Err(e) => eprintln!("Error during f32 inference: {}", e),
    }

    let weights_usize = vec![10, 20];
    let config_usize: ModelConfig<Vec<usize>> = ModelConfig::new(weights_usize, 2);
    let input_data_ok_2 = vec![0.5, 1.5];

    match config_usize.run_inference(&input_data_ok_2) {
        Ok(result) => println!("Inference successful with usize weights (Note: result type might be limited by function scope): {}", result),
        Err(e) => eprintln!("Error during usize inference: {}", e),
    }
}

use std::collections::HashMap;
use std::time::{Duration, Instant};

struct ProcessStats {
    cpu_percent: f32,
    memory_usage: u64,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut monitored_processes: HashMap<u32, ProcessStats> = HashMap::new();
    const MONITOR_INTERVAL: Duration = Duration::from_millis(500);

    println!("Starting real-time process monitor. Press Ctrl+C to exit.");

    loop {
        let start_time = Instant::now();

        let pids_to_monitor: Vec<u32> = vec![1, 2, 3];
        let mut current_stats: HashMap<u32, ProcessStats> = HashMap::new();

        for pid in pids_to_monitor {
            let cpu = (pid % 10) as f32 * 0.5 + 1.0;
            let mem_nsecs = Instant::now().elapsed().as_nanos();
            let mem: u64 = (pid * 1024) as u64 + ((mem_nsecs / 1000) as u64);
            current_stats.insert(pid, ProcessStats { cpu_percent: cpu, memory_usage: mem });
        }

        println!("n=========================================");
        for (pid, stats) in &current_stats {
            println!("PID: {}
  CPU: {:.1}%
  MEM: {} bytes", pid, stats.cpu_percent, stats.memory_usage);
        }
        println!("=========================================");

        let elapsed = start_time.elapsed();
        if elapsed < MONITOR_INTERVAL {
            std::thread::sleep(MONITOR_INTERVAL - elapsed);
        }
    }
}

use std::fmt::Debug;

struct Matrix<T: Debug + Copy> {
    data: Vec<T>,
    rows: usize,
    cols: usize,
}

impl<T: Debug + Copy> Matrix<T> {
    fn new(data: Vec<T>, rows: usize, cols: usize) -> Self {
        Matrix { data, rows, cols }
    }

    fn print_info(&self) -> String {
        format!("{}x{} matrix", self.rows, self.cols)
    }
}

fn process_all_matrices<T: Debug + Copy>(matrices: &[Matrix<T>]) -> Vec<String> where T: std::ops::Mul<Output = T> + std::fmt::Display {
    let mut results = Vec::new();
    for matrix in matrices.iter() {
        if matrix.rows > 0 && matrix.cols > 0 {
            results.push(format!("Processed: {}", matrix.print_info()));
        } else {
            results.push("Skipped zero-dimension matrix".to_string());
        }
    }
    results
}

fn main() {
    let m1 = Matrix::new(vec![5f64], 1, 1);
    let m2 = Matrix::new(vec![10.5f64], 2, 1);
    let m3 = Matrix::new(vec![], 0, 3);

    let data_set: Vec<Matrix<f64>> = vec![m1, m2, m3];
    let output = process_all_matrices(&data_set);

    for line in output {
        println!("{}", line);
    }
}

use std::fmt::{self, Display};
use std::error::Error;

struct KyberKey {
    material: Vec<u8>,
}
impl Display for KyberKey {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "KyberKey({})", self.material.len())
    }
}
impl std::fmt::Debug for KyberKey {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "KyberKey(len={})", self.material.len())
    }
}

fn process_key<T: AsRef<[u8]>>(key_data: T) -> Result<String, Box<dyn Error>> {
    let material = key_data.as_ref();
    if material.is_empty() {
        return Err("Key material cannot be empty".into());
    }
    Ok(format!("Successfully processed a {} byte key.", material.len()))
}

fn main() -> Result<(), Box<dyn Error>> {
    let short_key = vec![0xAA, 0xBB];
    let long_key = vec![0xFF; 128];

    println!("n--- Processing Short Key ---n");
    match process_key(short_key) {
        Ok(message) => println!("[SUCCESS] {}", message),
        Err(e) => eprintln!("[ERROR] {}", e),
    }

    println!("n--- Processing Long Key ---n");
    match process_key(long_key) {
        Ok(message) => println!("[SUCCESS] {}", message),
        Err(e) => eprintln!("[ERROR] {}", e),
    }

    let empty_key = vec![];
    println!("n--- Processing Empty Key ---n");
    match process_key(empty_key) {
        Ok(message) => println!("[SUCCESS] {}", message),
        Err(e) => eprintln!("[ERROR] {}", e),
    }

    Ok(())
}
